.darma-loader-darma-custom-358 {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
  width: 60px;
  aspect-ratio: 1;
  animation: darma-loader-darma-custom-358-l5-0 1s infinite steps(1);
}.darma-loader-darma-custom-358::before,.darma-loader-darma-custom-358::after {content: "";
  position: absolute;
  inset:0 50% 50% 0;
  transform-origin: bottom right;
  animation:darma-loader-darma-custom-358-l5-1 0.5s infinite linear alternate,darma-loader-darma-custom-358-l5-2 0.5s infinite steps(1) alternate;
}.darma-loader-darma-custom-358::after {--s:-1,-1;
}@keyframes darma-loader-darma-custom-358-l5-0 {0% {transform: scale(1, 1) rotate(0deg)}50% {transform: scale(1,-1) rotate(90deg)}}
@keyframes darma-loader-darma-custom-358-l5-1 {0% {transform: scale(var(--s,1)) perspective(150px) rotateX( 0deg)}100% {transform: scale(var(--s,1)) perspective(150px) rotateX(180deg)}}@keyframes darma-loader-darma-custom-358-l5-2 {0% {background:var(--loader-color, #16a34a)}50%{background:var(--loader-color, #16a34a)}}

